<template>
	<div
		:class="`text-[#b5b5b5a4] bg-clip-text inline-block ${!props.disabled ? 'animate-shine' : ''} ${props.className}`"
		:style="{
  backgroundImage: 'linear-gradient(120deg, rgba(255, 255, 255, 0) 40%, rgba(255, 255, 255, 0.8) 50%, rgba(255, 255, 255, 0) 60%)',
  backgroundSize: '200% 100%',
  WebkitBackgroundClip: 'text',
  animationDuration
}"
	>
		{{ props.text }}
	</div>
</template>

<script setup>
import { computed } from "vue";
const props = defineProps({
  text: { type: String, required: true, default: "" },
  disabled: { type: Boolean, required: false, default: false },
  speed: { type: Number, required: false, default: 5 },
  className: { type: String, required: false, default: "" }
});
const animationDuration = computed(() => `${props.speed}s`);
</script>

<style scoped>
@keyframes shine{0%{background-position:100%}to{background-position:-100%}}.animate-shine{animation:shine 5s linear infinite}
</style>
